#!/usr/bin/env node
// Generates public/donor-attribution.json — donor × face glyph-count matrix.
//
// Reads public/cp_map.json (downloaded from the GH release or generated by
// the build repo's emit_coverage_manifest.rb), groups codepoints by donor ×
// plane, writes the aggregated JSON.
//
// Single source of truth for the DonorAttribution SVG component.

import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const ROOT = path.resolve(__dirname, '..');
const PUBLIC = path.join(ROOT, 'public');

// Donor → family/category mapping for color coding.
// Source: sources/manifest.yml in the build repo (mirrored here for the website).
const DONOR_META = {
  'fsung-m':            { family: 'Full-Sung',           category: 'fsung' },
  'fsung-1':            { family: 'Full-Sung',           category: 'fsung' },
  'fsung-2':            { family: 'Full-Sung',           category: 'fsung' },
  'fsung-3':            { family: 'Full-Sung',           category: 'fsung' },
  'fsung-x':            { family: 'Full-Sung',           category: 'fsung' },
  'noto-sans':          { family: 'Noto Sans',           category: 'noto-sans' },
  'noto-serif-tangut':  { family: 'Noto Serif Tangut',   category: 'noto-serif' },
  'noto-serif-tai-yo':  { family: 'Noto Serif Tai Yo',   category: 'noto-serif' },
  'noto-sans-math':     { family: 'Noto Sans Math',      category: 'noto-sans' },
  'noto-music':         { family: 'Noto Music',          category: 'noto-sans' },
  'noto-sans-symbols':  { family: 'Noto Sans Symbols',   category: 'noto-sans' },
  'noto-sans-symbols-2':{ family: 'Noto Sans Symbols 2', category: 'noto-sans' },
  'noto-sans-cuneiform':{ family: 'Noto Sans Cuneiform', category: 'noto-sans' },
  'noto-color-emoji':   { family: 'Noto Color Emoji',    category: 'noto-sans' },
  'noto-emoji':         { family: 'Noto Emoji',          category: 'noto-sans' },
  'uni-hieroglyphica':  { family: 'UniHieroglyphica',    category: 'academic' },
  'egyptian-text':      { family: 'Egyptian Text',       category: 'academic' },
  'new-gardiner':       { family: 'NewGardiner',         category: 'academic' },
  'new-gardiner-non-core': { family: 'NewGardiner',      category: 'academic' },
  'kelly-tolong-4':     { family: 'Kelly Tolong',        category: 'academic' },
  'symbola':            { family: 'Symbola',             category: 'other' },
  'lentariso':          { family: 'Lentariso',           category: 'other' },
  'kedebideri':         { family: 'Kedebideri',          category: 'other' },
};

const PLANE_NAMES = { 0: 'BMP', 1: 'SMP', 2: 'SIP', 3: 'TIP', 14: 'SSP' };

const cpMapPath = path.join(PUBLIC, 'cp_map.json');
if (!fs.existsSync(cpMapPath)) {
  console.warn('donor-attribution: cp_map.json not found, skipping');
  process.exit(0);
}

const cpMap = JSON.parse(fs.readFileSync(cpMapPath, 'utf-8'));

// Aggregate: { donor_label → { plane → count } }
const byDonor = {};
for (const [cpStr, donorLabel] of Object.entries(cpMap)) {
  if (typeof donorLabel !== 'string') continue;
  const cp = parseInt(cpStr, 10);
  const plane = cp >> 16;
  const planeName = PLANE_NAMES[plane] || `Plane${plane}`;

  if (!byDonor[donorLabel]) {
    byDonor[donorLabel] = {};
  }
  byDonor[donorLabel][planeName] = (byDonor[donorLabel][planeName] || 0) + 1;
}

// Build output array, sorted by total codepoints descending
const donors = Object.entries(byDonor)
  .map(([label, byPlane]) => {
    const meta = DONOR_META[label] || { family: label, category: 'other' };
    const total = Object.values(byPlane).reduce((a, b) => a + b, 0);
    return {
      label,
      family: meta.family,
      category: meta.category,
      totalCodepoints: total,
      byPlane: { BMP: 0, SMP: 0, SIP: 0, TIP: 0, SSP: 0, ...byPlane },
    };
  })
  .sort((a, b) => b.totalCodepoints - a.totalCodepoints);

const data = {
  generatedAt: new Date().toISOString(),
  source: 'cp_map.json',
  donorCount: donors.length,
  donors,
};

const outPath = path.join(PUBLIC, 'donor-attribution.json');
fs.writeFileSync(outPath, JSON.stringify(data, null, 2) + '\n');
console.log(`donor-attribution: wrote ${path.relative(ROOT, outPath)} (${donors.length} donors)`);
